"""
边界值测试: 用户手机号登录
接口: POST /api/v1/auth/login
用例: boundary | 期望: 201
"""

def test_phone_user_login_boundary(base_url, auth_headers):
    """边界值测试: 用户手机号登录"""

    url = f"{base_url}/api/v1/auth/login"
    headers = {**auth_headers, **{
            "Content-Type": "application/json"
    }}
    body = {
            "phone": "",
            "code": "AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA"
    }

    resp = requests.post(url, headers=headers, json=body)

    assert resp.status_code == 201, f"201 expected, got {resp.status_code}"

